mapper.select:
SELECT ai.resource_id AS resourceId, COALESCE(oq.name, c.name, so.name, ci.name, '') AS resourceName, UPPER(ai.type) AS resourceType, u.name AS applicant, ai.submit_time AS submitTime, ai.approval_status AS approvalOperation, ai.approval_status AS dataResult, NULL AS approvalTaskId, ai.current_node_id AS approvalNodeId, ai.id AS approvalInstanceId, ai.submitter_id AS approvalId, afv.flow_id AS approvalFlowId, afv.id AS approvalFlowVersionId FROM approval_instance ai INNER JOIN approval_flow_version afv ON afv.id = ai.flow_version_id LEFT JOIN sys_user u ON u.id = ai.submitter_id LEFT JOIN opportunity_quotation oq ON ai.resource_id = oq.id AND ai.type IN ('quotation', 'quote') LEFT JOIN contract c ON ai.resource_id = c.id AND ai.type = 'contract' LEFT JOIN sales_order so ON ai.resource_id = so.id AND ai.type = 'order' LEFT JOIN contract_invoice ci ON ai.resource_id = ci.id AND ai.type = 'invoice' WHERE ai.submitter_id = #{submitterId}
AND ai.type = #{resourceType}
AND COALESCE(oq.name, c.name, so.name, ci.name) LIKE CONCAT('%', #{keyword}, '%')
ORDER BY ai.update_time DESC, ai.id DESC

